-- Basic Policies

-- Profiles: Anyone authenticated can read profiles (for supervisors to see employees)
CREATE POLICY "Authenticated users can read profiles" ON public.profiles
    FOR SELECT TO authenticated USING (true);

-- Profiles: Only admins can insert/update/delete
CREATE POLICY "Admins can manage profiles" ON public.profiles
    FOR ALL TO authenticated USING (
        (SELECT role FROM public.profiles WHERE id = auth.uid()) = 'admin'
    );

-- QR Codes: Users can see their own, admins/supervisors can see all
CREATE POLICY "Users can view own QR, Admins/Supervisors view all" ON public.qr_codes
    FOR SELECT TO authenticated USING (
        user_id = auth.uid() OR 
        (SELECT role FROM public.profiles WHERE id = auth.uid()) IN ('admin', 'supervisor')
    );

-- QR Codes: Admins can manage
CREATE POLICY "Admins can manage QR codes" ON public.qr_codes
    FOR ALL TO authenticated USING (
        (SELECT role FROM public.profiles WHERE id = auth.uid()) = 'admin'
    );

-- Attendance: Users can see their own, admins/supervisors can see all
CREATE POLICY "Users can view own attendance, Admins/Supervisors view all" ON public.attendance
