        user_id = auth.uid() OR 
        (SELECT role FROM public.profiles WHERE id = auth.uid()) IN ('admin', 'supervisor')
    );

-- Attendance: Admins and Supervisors can insert
CREATE POLICY "Admins and Supervisors can insert attendance" ON public.attendance
    FOR INSERT TO authenticated WITH CHECK (
        (SELECT role FROM public.profiles WHERE id = auth.uid()) IN ('admin', 'supervisor')
    );
